mlflow_reachable = False
for attempt in range(3):
    try:
        run = mlflow.get_run(run_id)
        if run.info.status == "RUNNING":
            mlflow_reachable = True
            return state
        else:
            return None  # Run ended, don't resume
    except Exception:
        if attempt < 2:
            time.sleep(10 * (attempt + 1))
        else:
            logger.warning("MLflow unreachable after 3 attempts for run %s", run_id)

# Checkpoint-based fallback when MLflow is down
if not mlflow_reachable:
    epoch_pth = Path(state.get("checkpoint_dir", "")) / "epoch_latest.pth"
    if epoch_pth.exists():
        logger.warning("MLflow unreachable but checkpoint exists — resuming from file")
        return state
    else:
        logger.warning("MLflow unreachable and no checkpoint — starting fresh")
        return None

