class StructuredEventLogger: def __init__(self, output_dir: Path | None): self._output_dir = output_dir self._events_path = output_dir / "events.jsonl" if output_dir else None self._heartbeat_path = output_dir / "heartbeat.json" if output_dir else None
def log_event(self, event_type: str, payload: dict) -> None: if not self._events_path: return entry = {"timestamp": datetime.now(timezone.utc).isoformat(), "event_type": event_type, **payload} with self._events_path.open("a", encoding="utf-8") as f: f.write(json.dumps(entry) + "\n")
def update_heartbeat(self, **kwargs) -> None: if not self._heartbeat_path: return data = {"timestamp": datetime.now(timezone.utc).isoformat(), "status": "training", **kwargs} self._heartbeat_path.write_text(json.dumps(data), encoding="utf-8")
Wire into trainer.py fit() loop (SUPPLEMENTS MLflow, does NOT replace): - trainer.py:751 (epoch loop start): log_event("epoch_start", {"epoch": epoch}) - trainer.py:901 (after MLflow logging): log_event("epoch_end", {**epoch_log}) - trainer.py:901 (same location): update_heartbeat(epoch=epoch, loss=train_loss) Note: trainer.py already logs extensively via self.tracker (MLflow). StructuredEventLogger adds a SECOND output channel (JSONL on GCS mount) for LLM-parseable monitoring. This is intentional redundancy.
